const checkpoints = [];

const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const readingList = JSON.parse(localStorage.getItem('reading_list_items') || '[]');

// Find the latest Taurus daily horoscope (treated as "today")
const taurusDaily = articles.filter(a => a.article_type === 'daily_horoscope' && a.zodiac_sign === 'taurus');
let mainArticle = null;
if (taurusDaily.length > 0) {
  mainArticle = taurusDaily.slice().sort((a, b) => (b.publish_date || '').localeCompare(a.publish_date || '') )[0];
}

// Helper: check if an article is saved to reading list
function isSaved(articleId) {
  return !!readingList.find(ri => ri.article_id === articleId);
}

let mainSaved = false;
let savedEligibleCount = 0;
let top2AllSaved = false;

if (mainArticle) {
  // Check main Taurus daily horoscope saved
  mainSaved = isSaved(mainArticle.id);

  // Compute eligible related articles: explicitly related, rating >= 4.0, sorted by rating desc
  const related = Array.isArray(mainArticle.related_article_ids)
    ? mainArticle.related_article_ids
        .map(id => articles.find(a => a.id === id))
        .filter(a => !!a)
    : [];

  const eligibleRelated = related.filter(a => (a.rating || 0) >= 4.0);
  const eligibleSorted = eligibleRelated.slice().sort((a, b) => (b.rating || 0) - (a.rating || 0));

  const top2 = eligibleSorted.slice(0, 2);

  // Count how many eligible related are saved (for "at least 2" check)
  savedEligibleCount = eligibleRelated.filter(a => isSaved(a.id)).length;

  // Check if the top 2 highest-rated eligible related articles are all saved
  if (top2.length === 2) {
    top2AllSaved = top2.every(a => isSaved(a.id));
  }
}

// CP1 (0.3): Taurus daily horoscope (latest) is saved to reading list
checkpoints.push({ passed: !!mainArticle && mainSaved, weight: 0.3 });

// CP2 (0.3): At least 2 related articles with rating >= 4.0 from that horoscope are saved
checkpoints.push({ passed: savedEligibleCount >= 2, weight: 0.3 });

// CP3 (0.4): The top 2 highest-rated eligible related articles are saved
checkpoints.push({ passed: top2AllSaved, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const spreads = JSON.parse(localStorage.getItem('tarot_spreads') || '[]');
const favorites = JSON.parse(localStorage.getItem('favorite_items') || '[]');

// Approximate search results: beginner-level love spreads, sorted by relevance
let loveBeginner = spreads.filter(s => s.difficulty === 'beginner' && String(s.theme || '').toLowerCase() === 'love');
// Relevance sort: rating desc, then created_at desc (to mirror BusinessLogic.searchTarotSpreads)
loveBeginner = loveBeginner.slice().sort((a, b) => {
  const rdiff = (b.rating || 0) - (a.rating || 0);
  if (rdiff !== 0) return rdiff;
  return (b.created_at || '').localeCompare(a.created_at || '');
});

const firstTwo = loveBeginner.slice(0, 2);
let targetSpread = null;

if (firstTwo.length === 2) {
  const s1 = firstTwo[0];
  const s2 = firstTwo[1];
  const maxTime = 15;
  const s1Ok = (s1.estimated_reading_time_minutes || 0) <= maxTime;
  const s2Ok = (s2.estimated_reading_time_minutes || 0) <= maxTime;

  if (s1Ok && s2Ok) {
    // Both within time: choose one with more cards
    targetSpread = s1.number_of_cards >= s2.number_of_cards ? s1 : s2;
  } else if (s1Ok || s2Ok) {
    // Only one within time: choose that one
    targetSpread = s1Ok ? s1 : s2;
  } else {
    // Both exceed time: choose the one with shorter estimated time
    targetSpread = (s1.estimated_reading_time_minutes || 0) <= (s2.estimated_reading_time_minutes || 0) ? s1 : s2;
  }
}

let targetFavorited = false;
if (targetSpread) {
  targetFavorited = favorites.some(f => f.content_type === 'tarot_spread' && f.content_id === targetSpread.id);
}

// Single checkpoint: correct spread (per rule) is favorited
checkpoints.push({ passed: !!targetSpread && targetFavorited, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const collections = JSON.parse(localStorage.getItem('collections') || '[]');
const collectionItems = JSON.parse(localStorage.getItem('collection_items') || '[]');

// Find all Capricorn career weekly horoscopes (any month/year)
const capCareerWeekly = articles.filter(a => a.article_type === 'career_horoscope' && a.zodiac_sign === 'capricorn');

// If multiple months/years existed, we'd group by (month, year), but in practice the dataset uses April 2026
let targetMonth = null;
let targetYear = null;
if (capCareerWeekly.length > 0) {
  // Choose the month/year that has the most weekly entries (approx upcoming month group)
  const groupMap = {};
  capCareerWeekly.forEach(a => {
    const key = `${a.year || ''}-${a.month || ''}`;
    if (!groupMap[key]) groupMap[key] = [];
    groupMap[key].push(a);
  });
  let bestKey = null;
  let bestLen = 0;
  Object.keys(groupMap).forEach(k => {
    const len = groupMap[k].length;
    if (len > bestLen) { bestLen = len; bestKey = k; }
  });
  if (bestKey) {
    const [yStr, mStr] = bestKey.split('-');
    targetYear = parseInt(yStr, 10);
    targetMonth = parseInt(mStr, 10);
  }
}

let chosenCollection = null;
let weeklyInCollection = [];

if (targetMonth && targetYear) {
  const monthlyCapCareer = capCareerWeekly.filter(a => a.month === targetMonth && a.year === targetYear);

  // Find all collections named "Capricorn Career" and pick the most recently created as the relevant one
  const named = collections.filter(c => c.name === 'Capricorn Career');
  if (named.length > 0) {
    chosenCollection = named.slice().sort((a, b) => (b.created_at || '').localeCompare(a.created_at || ''))[0];

    const itemsForCollection = collectionItems.filter(ci => ci.collection_id === chosenCollection.id);
    const articleIdsInCollection = itemsForCollection.map(ci => ci.article_id);

    weeklyInCollection = monthlyCapCareer.filter(a => articleIdsInCollection.includes(a.id));
  }
}

const distinctWeeks = new Set(weeklyInCollection.map(a => a.week_number)).size;
const countWeekly = weeklyInCollection.length;

// CP1 (0.4): A 'Capricorn Career' collection exists and contains at least one Capricorn career weekly horoscope from the target month
checkpoints.push({
  passed: !!chosenCollection && countWeekly >= 1,
  weight: 0.4
});

// CP2 (0.3): Collection contains at least 3 distinct weekly Capricorn career horoscopes for the same month/year
checkpoints.push({
  passed: distinctWeeks >= 3,
  weight: 0.3
});

// CP3 (0.3): Exactly 3 such weekly horoscopes are included (no extra weekly entries beyond the required three)
checkpoints.push({
  passed: countWeekly === 3 && distinctWeeks === 3,
  weight: 0.3
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const favorites = JSON.parse(localStorage.getItem('favorite_items') || '[]');

// Mercury retrograde articles in the last ~12 months: use article_type filter; dataset dates are already within the range
const mercuryArticles = articles.filter(a => a.article_type === 'mercury_retrograde');

// Sort by rating desc
const sorted = mercuryArticles.slice().sort((a, b) => (b.rating || 0) - (a.rating || 0));

// Eligible (rating >= 4.5), take first 3
const topCandidates = sorted.filter(a => (a.rating || 0) >= 4.5).slice(0, 3);

// Check that all topCandidates are favorited as articles
const allTopFavorited = topCandidates.length === 3 && topCandidates.every(a =>
  favorites.some(f => f.content_type === 'article' && f.content_id === a.id)
);

checkpoints.push({ passed: allTopFavorited, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const prefsList = JSON.parse(localStorage.getItem('content_preferences') || '[]');
const prefs = prefsList[0] || null;

let zodiacOk = false;
let interestsOk = false;
let mixOk = false;
let lengthOk = false;

if (prefs) {
  // CP data
  zodiacOk = prefs.primary_zodiac_sign === 'libra';

  const interests = Array.isArray(prefs.interests) ? prefs.interests : [];
  const lowerInterests = interests.map(i => String(i).toLowerCase());

  const required = [
    'love',
    'career',
    'tarot spreads',
    'tarot_spreads',
    'daily horoscopes',
    'daily_horoscopes',
    'moon phases',
    'moon_phases'
  ];

  const hasTopic = (topicVariants) => {
    return lowerInterests.some(val =>
      topicVariants.some(req => val.indexOf(req) !== -1)
    );
  };

  const loveOk = hasTopic(['love']);
  const careerOk = hasTopic(['career']);
  const tarotSpreadsOk = hasTopic(['tarot spreads', 'tarot_spreads']);
  const dailyHoroscopesOk = hasTopic(['daily horoscopes', 'daily_horoscopes']);
  const moonPhasesOk = hasTopic(['moon phases', 'moon_phases']);

  interestsOk = interests.length >= 5 && loveOk && careerOk && tarotSpreadsOk && dailyHoroscopesOk && moonPhasesOk;

  const tarotPct = prefs.tarot_content_percentage;
  const astroPct = prefs.astrology_content_percentage;
  mixOk = tarotPct === 70 && astroPct === 30;

  lengthOk = prefs.article_length_preference === 'short';
}

checkpoints.push({ passed: zodiacOk, weight: 0.25 });
checkpoints.push({ passed: interestsOk, weight: 0.25 });
checkpoints.push({ passed: mixOk, weight: 0.25 });
checkpoints.push({ passed: lengthOk, weight: 0.25 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const comments = JSON.parse(localStorage.getItem('comments') || '[]');

// Find compatibility articles for Leo–Aquarius
const compatArticles = articles.filter(a => {
  if (a.article_type !== 'compatibility') return false;
  const s1 = a.compatibility_sign_one;
  const s2 = a.compatibility_sign_two;
  return (
    (s1 === 'leo' && s2 === 'aquarius') ||
    (s1 === 'aquarius' && s2 === 'leo')
  );
});

// Sort by most commented (comment_count desc)
compatArticles.sort((a, b) => (b.comment_count || 0) - (a.comment_count || 0));

// Choose the first article with reading_time_minutes <= 10 and comment_count >= 8
let targetArticle = null;
for (const a of compatArticles) {
  if ((a.reading_time_minutes || 0) <= 10 && (a.comment_count || 0) >= 8) {
    targetArticle = a;
    break;
  }
}

let commentOk = false;
if (targetArticle) {
  const targetComments = comments.filter(c => c.article_id === targetArticle.id && c.author_name === 'Test Reader');
  commentOk = targetComments.some(c => {
    const text = String(c.content || '').toLowerCase();
    return text.includes('saving this') && text.includes('compatibility reading') && text.includes('future reference');
  });
}

checkpoints.push({ passed: !!targetArticle && commentOk, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const cards = JSON.parse(localStorage.getItem('tarot_cards') || '[]');
const prompts = JSON.parse(localStorage.getItem('tarot_card_prompts') || '[]');
const notes = JSON.parse(localStorage.getItem('notes') || '[]');

// Find the Tower card: major arcana with a keyword containing 'upheaval', or fallback to id 'the_tower'
let towerCard = cards.find(c => c.arcana_type === 'major_arcana' && Array.isArray(c.keywords) && c.keywords.some(k => String(k).toLowerCase().includes('upheaval')));
if (!towerCard) {
  towerCard = cards.find(c => c.id === 'the_tower');
}

let firstPrompt = null;
if (towerCard) {
  const towerPrompts = prompts
    .filter(p => p.tarot_card_id === towerCard.id)
    .sort((a, b) => (a.order_index || 0) - (b.order_index || 0));
  firstPrompt = towerPrompts[0] || null;
}

let noteShortenedOk = false;
let noteLengthBehaviorOk = false;

if (firstPrompt) {
  const relatedNotes = notes.filter(n => n.source_type === 'tarot_card_prompt' && n.source_reference_id === firstPrompt.id);

  if (relatedNotes.length > 0) {
    noteShortenedOk = relatedNotes.some(n => {
      const content = String(n.content || '');
      const withinLimit = content.length <= 120;
      const isSubstring = String(firstPrompt.text || '').includes(content);
      return withinLimit && isSubstring;
    });

    // If original prompt is longer than 120 chars, ensure at least one saved note is actually shorter
    const originalLen = String(firstPrompt.text || '').length;
    if (originalLen > 120) {
      noteLengthBehaviorOk = relatedNotes.some(n => {
        const content = String(n.content || '');
        const charCount = typeof n.character_count === 'number' ? n.character_count : content.length;
        return content.length < originalLen && content.length <= 120 && charCount <= 120;
      });
    } else {
      // If original is already <= 120, just require it respects the limit
      noteLengthBehaviorOk = relatedNotes.some(n => (String(n.content || '').length <= 120));
    }
  }
}

// CP1 (0.5): A note exists for the first Tower prompt, and its content is a ≤120-char substring of the original prompt
checkpoints.push({ passed: !!firstPrompt && noteShortenedOk, weight: 0.5 });

// CP2 (0.5): If the original prompt is >120 chars, at least one saved note is actually shorter (and ≤120 chars) for that prompt
checkpoints.push({ passed: !!firstPrompt && noteLengthBehaviorOk, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const events = JSON.parse(localStorage.getItem('moon_events') || '[]');
const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const entries = JSON.parse(localStorage.getItem('ritual_planner_entries') || '[]');

// Find the Full Moon in Aries event in October 2023
const moonEvent = events.find(e =>
  e.moon_phase === 'full_moon' &&
  e.zodiac_sign === 'aries' &&
  e.calendar_month === 10 &&
  e.calendar_year === 2023
);

let ritualArticle = null;
if (moonEvent && Array.isArray(moonEvent.related_article_ids)) {
  const relatedArticles = moonEvent.related_article_ids
    .map(id => articles.find(a => a && a.id === id))
    .filter(a => !!a);
  ritualArticle = relatedArticles.find(a => a.article_type === 'ritual_guide') || relatedArticles[0] || null;
}

let timingOk = false;
let noteOk = false;

if (moonEvent && ritualArticle) {
  const targetDateStr = '2023-10-28';

  const matchingEntries = entries.filter(e => e.article_id === ritualArticle.id);

  const matchingOnDate = matchingEntries.filter(e => {
    const s = String(e.scheduled_start || '');
    // Accept either plain date-time or with Z, as long as it clearly includes the date and 21:00 (9 PM)
    return s.includes(targetDateStr) && s.includes('21:00');
  });

  if (matchingOnDate.length > 0) {
    timingOk = true;
    noteOk = matchingOnDate.some(e => {
      const note = String(e.note || '').toLowerCase();
      const hasCandles = note.includes('candle');
      const hasJournaling = note.includes('journal');
      const mentionsAriesOrFullMoon = note.includes('aries') || note.includes('full moon') || note.includes('full-moon');
      return hasCandles && hasJournaling && mentionsAriesOrFullMoon;
    });
  }
}

// CP1 (0.6): A ritual planner entry exists for the ritual guide on 2023-10-28 at 21:00 (9 PM)
checkpoints.push({ passed: !!moonEvent && !!ritualArticle && timingOk, weight: 0.6 });

// CP2 (0.4): That entry’s note mentions candles and journaling (and references Aries/full moon)
checkpoints.push({ passed: !!moonEvent && !!ritualArticle && noteOk, weight: 0.4 });

